-- Create "quality_eval_samples" table
CREATE TABLE "quality_eval_samples" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "feedback_id" bigint NOT NULL,
  "request_id" character varying NOT NULL,
  "decision_id" bigint NOT NULL,
  "attempt_no" bigint NOT NULL DEFAULT 1,
  "account_id" bigint NOT NULL,
  "provider_id" bigint NOT NULL,
  "model" character varying NOT NULL DEFAULT '',
  "source_endpoint" character varying NOT NULL DEFAULT '',
  "sample_request_hash" character varying NOT NULL,
  "sample_payload_ciphertext" bytea NOT NULL,
  "payload_version" character varying NOT NULL DEFAULT 'v1',
  "captured_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "qualityevalsample_account_id_model_captured_at" to table: "quality_eval_samples"
CREATE INDEX "qualityevalsample_account_id_model_captured_at" ON "quality_eval_samples" ("account_id", "model", "captured_at");
-- Create index "qualityevalsample_decision_id" to table: "quality_eval_samples"
CREATE INDEX "qualityevalsample_decision_id" ON "quality_eval_samples" ("decision_id");
-- Create index "qualityevalsample_feedback_id" to table: "quality_eval_samples"
CREATE UNIQUE INDEX "qualityevalsample_feedback_id" ON "quality_eval_samples" ("feedback_id");
-- Create index "qualityevalsample_request_id_attempt_no" to table: "quality_eval_samples"
CREATE INDEX "qualityevalsample_request_id_attempt_no" ON "quality_eval_samples" ("request_id", "attempt_no");
-- Create index "qualityevalsample_sample_request_hash" to table: "quality_eval_samples"
CREATE INDEX "qualityevalsample_sample_request_hash" ON "quality_eval_samples" ("sample_request_hash");
-- Create "quality_evaluations" table
CREATE TABLE "quality_evaluations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "feedback_id" bigint NOT NULL,
  "request_id" character varying NOT NULL,
  "decision_id" bigint NOT NULL,
  "attempt_no" bigint NOT NULL DEFAULT 1,
  "account_id" bigint NOT NULL,
  "provider_id" bigint NOT NULL,
  "model" character varying NOT NULL DEFAULT '',
  "source_endpoint" character varying NOT NULL DEFAULT '',
  "sample_request_hash" character varying NOT NULL,
  "judge_model" character varying NOT NULL DEFAULT '',
  "score" double precision NOT NULL DEFAULT 0,
  "rubric_json" jsonb NULL,
  "judged_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "qualityevaluation_account_id_model_judged_at" to table: "quality_evaluations"
CREATE INDEX "qualityevaluation_account_id_model_judged_at" ON "quality_evaluations" ("account_id", "model", "judged_at");
-- Create index "qualityevaluation_decision_id" to table: "quality_evaluations"
CREATE INDEX "qualityevaluation_decision_id" ON "quality_evaluations" ("decision_id");
-- Create index "qualityevaluation_feedback_id" to table: "quality_evaluations"
CREATE UNIQUE INDEX "qualityevaluation_feedback_id" ON "quality_evaluations" ("feedback_id");
-- Create index "qualityevaluation_judge_model_judged_at" to table: "quality_evaluations"
CREATE INDEX "qualityevaluation_judge_model_judged_at" ON "quality_evaluations" ("judge_model", "judged_at");
-- Create index "qualityevaluation_sample_request_hash" to table: "quality_evaluations"
CREATE INDEX "qualityevaluation_sample_request_hash" ON "quality_evaluations" ("sample_request_hash");
